-- ============================================================
-- Этап 5 «Крыша» (roof) проекта Homesteader's Cabin — эталонный
-- контент из ЭТАП5_Крыша.md. Реальные данные: стропила 50×250
-- шаг 610 мм, угол 45° (скат 12/12), конёк 50×300, обшивка 18 мм.
-- Шаг 1 «Безопасность работы на высоте» — is_mandatory=true.
-- Safety_text про высоту/страховку — у шагов 2–5. Скрипт покупки
-- стропил/конька/кровли — в hint шага 5.
-- Идемпотентно: пересоздаёт только шаги этапа roof (id ...315).
-- ============================================================

do $do$
begin
  if not exists (select 1 from stages
                 where id = 'de300000-0000-4000-8000-000000000315') then
    return;
  end if;

  update stages set intro = '🔴 Красный этап, и он особенный: когда встанет крыша, дом впервые станет НАСТОЯЩИМ домом — с силуэтом, который узнаёшь издалека. Крутая двускатная крыша под углом 45° — это и красиво (тот самый стильный силуэт), и практично: снег с такой крыши скатывается сам, не накапливается, не давит. Для нашей зимы — идеально.

Крыша держится на стропилах — наклонных досках, которые идут от стен к коньку (верхнему ребру). Стропило — это наклонная балка крыши. Они как рёбра, а конёк — как позвоночник.

Это самый опасный этап по высоте. Работа наверху, на краю, с тяжёлыми досками. Здесь безопасность важнее скорости. Никакой спешки, только со страховкой, в устойчивой обуви, и лучше не в одиночку. Я буду напоминать про это на каждом шаге.

Займёт около 5 дней. Тебе нужен помощник — стропила тяжёлые, одному наверху опасно. Когда накроешь дом — это будет момент огромной гордости: «я построил дом под крышу своими руками».'
  where id = 'de300000-0000-4000-8000-000000000315';

  delete from steps where stage_id = 'de300000-0000-4000-8000-000000000315';

  insert into steps (id, stage_id, sort, title, why_text, prep_text, actions, tools,
    safety_text, self_check, hint, common_mistake, is_mandatory, helpers_needed) values
  ('de300000-0000-4000-8000-000000000461',
   'de300000-0000-4000-8000-000000000315', 1,
   'Безопасность работы на высоте',
   'Крыша — это высота 3-5 метров. Большинство серьёзных травм на стройке — падения с крыши. 5 минут на безопасность спасают здоровье и жизнь.',
   'Купи заранее: строительные леса или устойчивые козлы (аренда/покупка) — НЕ шаткая стремянка; страховочная привязь с верёвкой (для работы на скате) — недорого, но спасает; каска, обувь с нескользящей подошвой, перчатки.',
   '["Не работай на крыше в дождь, ветер, гололёд — скользко, сдувает. Жди сухой погоды.","Устойчивая опора: леса или прочный настил, а не «встал на две доски».","Страховка на скате: когда лазаешь по стропилам — привязь к коньку. Скат 45° крутой, соскользнуть легко.","Инструмент на привязи или в сумке — упавший сверху молоток опасен для того, кто внизу.","Не в одиночку: наверху всегда должен быть кто-то рядом или внизу.","Устал — слезай. Усталость + высота = падение."]',
   '{"строительные леса или козлы","страховочная привязь","каска","обувь с нескользящей подошвой","перчатки"}',
   '',
   '["Есть устойчивые леса/козлы (не шаткие)","Есть страховочная привязь","Нескользящая обувь, каска","Работаю не один, погода сухая"]',
   '', '', true, 1),
  ('de300000-0000-4000-8000-000000000462',
   'de300000-0000-4000-8000-000000000315', 2,
   'Ставим коньковый брус',
   'Конёк — верхнее ребро крыши, «позвоночник», к которому крепятся все стропила вверху. Ставим его первым, по центру дома, на нужной высоте.',
   'Купи заранее (из сметы): коньковый брус 50×300 мм (2×12) — по длине дома; доски на временные вертикальные стойки-опоры под конёк; крепёж.',
   '["Поставь по центру дома (по коньковой линии) временные вертикальные стойки нужной высоты — они подержат конёк, пока не встали стропила.","Уложи на них коньковый брус 50×300 вдоль всего дома, точно по центру.","Проверь уровнем: конёк строго горизонтален и точно по центру (иначе скаты будут разной длины).","Закрепи временно — потом стропила зафиксируют его окончательно."]',
   '{"уровень","рулетка 10 м","молоток или шуруповёрт"}',
   'Работа наверху: только с устойчивых лесов или козел, не в дождь, ветер или гололёд.',
   '["Коньковый брус 50×300 стоит по центру дома","Строго горизонтален (по уровню)","Высота по чертежу (для угла 45°)","Временно закреплён"]',
   'Высоту конька бери по чертежу — от неё зависит угол 45°. Если конёк ниже/выше — угол «уедет», и стропила не сойдутся с запилами. Меряй точно.',
   'Поставить конёк не по центру или не горизонтально. Тогда один скат длиннее другого, крыша кривая. Проверяй центр и уровень.',
   false, 1),
  ('de300000-0000-4000-8000-000000000463',
   'de300000-0000-4000-8000-000000000315', 3,
   'Изготавливаем и ставим стропила',
   'Стропила — наклонные «рёбра» крыши. Делаем их по шаблону (все одинаковые) и ставим от стен к коньку. Это основная работа этапа.',
   'Купи заранее: доски 50×250 мм (2×10) — на стропила, длина ~2,86 м каждое; металлические крепления для стропил, крепёж.',
   '["Сделай первое стропило как шаблон. Отмерь длину (~2,86 м), сделай запилы: сверху — под углом к коньку (45°), снизу — «птичий рот» (birdsmouth) — вырез, которым стропило садится на стену. Размеры запилов — по чертежу.","Приложи первое стропило по месту — проверь, что садится точно (верх к коньку, низ на стену). Если да — по нему размечай остальные (все одинаковые).","Напили нужное число стропил по шаблону.","Размечай на стенах и коньке места стропил — через 61 см (шаг 610, как всё остальное).","Ставь стропила парами (левое + правое сходятся на коньке), крепи вверху к коньку, внизу к стене металлическими креплениями. Работай вдвоём: один держит, другой крепит."]',
   '{"ножовка или циркулярка","угольник","карандаш","рулетка 10 м"}',
   'На скате — только со страховочной привязью к коньку. Ставь стропила вдвоём: один держит, другой крепит.',
   '["Первое стропило-шаблон подошло по месту","Все стропила напилены одинаково по шаблону","Стропила стоят парами через 61 см","Верх закреплён к коньку, низ к стене (креплениями)"]',
   '«Птичий рот» (birdsmouth) — это треугольный вырез внизу стропила, которым оно «садится» на стену, как седло. Без него стропило будет опираться уголком и съезжать. Вырезай по шаблону аккуратно.',
   'Делать каждое стропило «по месту» на глаз — получатся разной длины, крыша волной. Делай ВСЕ по одному шаблону (первому проверенному стропилу).',
   false, 1),
  ('de300000-0000-4000-8000-000000000464',
   'de300000-0000-4000-8000-000000000315', 4,
   'Обшиваем крышу (сплошной настил)',
   'Поверх стропил кладём сплошной настил из фанеры — основа, на которую ляжет кровля. Он же связывает стропила в жёсткую конструкцию.',
   'Купи заранее: фанера/OSB 18 мм — на обшивку крыши, листы 122×244; саморезы/гвозди.',
   '["Клади листы фанеры на стропила снизу вверх, вдоль ската. Край листа — на середину стропила.","Прибивай к каждому стропилу, край листа — обязательно на стропило (не на весу).","Швы вразбежку (как везде). Начинай каждый ряд со смещением.","Дойди до конька с обеих сторон."]',
   '{"шуруповёрт","страховочная привязь"}',
   'Наступай только на прибитые листы — непришитый лист или шаг «на весу» = провал вниз. Страховка пристёгнута всегда.',
   '["Фанера прибита к каждому стропилу","Края листов на стропилах, швы вразбежку","Оба ската обшиты до конька","Работал со страховкой"]',
   'Работай снизу вверх — уже прибитые листы служат тебе опорой для следующих. Всегда стой на прибитом, страховка пристёгнута.',
   'Наступать на непришитый лист или на весу — провалишься. Только на закреплённое.',
   false, 1),
  ('de300000-0000-4000-8000-000000000465',
   'de300000-0000-4000-8000-000000000315', 5,
   'Укладываем кровлю и гидроизоляцию',
   'Поверх настила — гидроизоляция и кровельный материал. Это то, что защищает дом от дождя и снега. Дом наконец «под крышей».',
   'Купи заранее: гидроизоляционная плёнка (подкровельная) — по площади крыши; кровля — металлочерепица / профлист / ондулин (выбор в конфигураторе); обрешётка (бруски), крепёж кровли; коньковый элемент, планки.',
   '["Раскатай по настилу подкровельную гидроизоляцию снизу вверх, внахлёст, закрепи.","Прибей обрешётку (бруски поперёк) — на неё ляжет кровля, и будет вентзазор.","Укладывай кровельные листы снизу вверх, внахлёст (чтобы вода стекала по нахлёсту, не затекала), крепи специальными саморезами.","Закрой конёк коньковым элементом (планка сверху, закрывает стык скатов).","Проверь — нет ли щелей, где затечёт."]',
   '{"шуруповёрт","молоток","степлер","нож"}',
   'Работа на скате крыши: страховочная привязь обязательна, только в сухую безветренную погоду. Инструмент — на привязи или в сумке, внизу люди.',
   '["Гидроизоляция уложена внахлёст","Обрешётка прибита","Кровля уложена снизу вверх, внахлёст","Конёк закрыт, щелей нет"]',
   'Кровлю кладут ВСЕГДА снизу вверх и с нахлёстом «как чешуя» — верхний ряд перекрывает нижний, вода стекает поверху. Наоборот нельзя — затечёт под листы.

СКРИПТ — покупка стропил, конька и кровли. На крышу идёт качественная доска (несущая!) и кровельный материал; обман — на длине стропил, количестве кровли, сорте. Про доски 50×250 (стропила) и 50×300 (конёк): «Сухая, сорт 1, без продольных трещин?» — стропила несут снег, брак недопустим; осмотри каждую: продольная трещина или крупный сук = брак. Кубатура 50×250: ≈13 досок в кубе; 50×300: ≈11 досок в кубе. Про кровлю: посчитай площадь крыши с запасом 10-15% (на нахлёсты и подрезку); «Полный комплект — листы, коньковый элемент, саморезы, планки?» — часто планки/конёк продают отдельно, уточни, чтоб не докупать; металлочерепица/профлист — с завода по твоим размерам (меньше отходов) или стандартными листами. Красные флаги: стропильная доска с трещинами (опасно под снегом!), кровля «б/у» или с царапинами до металла (заржавеет), «конёк докупите сами» без предупреждения. Ориентир: крыша — крупная статья (стропила + кровля + гидроизоляция); кровельный материал выбираешь в конфигураторе по цене/сложности (ондулин проще и дешевле, металлочерепица красивее и дороже).',
   'Мало нахлёста или крепёж не в том месте — потечёт в дождь. Следуй инструкции своей кровли по нахлёсту и точкам крепления.',
   false, 1);
end
$do$;
